{
  "name": "State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all, including those above federal poverty line (over half of 2025 clients had income above FPL)[2]",
    "asset_limits": "No asset limits or tests",
    "other_requirements": ["Must be a Wisconsin Medicare beneficiary, family member, or caregiver[1][2][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased one-on-one counseling on Medicare costs, eligibility, enrollment, plan options (e.g., Medicare Advantage, Part D, Medigap), programs to lower costs (e.g., Medicare Savings Program, Extra Help, Medicaid); assistance with appeals, bills, employer/long-term care insurance; outreach events and education; average call 35-50 minutes, 40% in-person[1][2][3]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": [
      "Phone: 1-800-242-1060 (Medigap Helpline) or 1-855-677-2783 (Medigap/Part D Hotline), TTY 711[1][7]",
      "In-person: Local Aging and Disability Resource Centers (ADRCs), county aging offices, Tribal offices, senior centers, clinics[2]",
      "Email: BOALTCMedigap@wisconsin.gov[1]"
    ],
    "processing_time": "Immediate counseling upon contact (calls 35-50 min, in-person appointments scheduled locally)[2]",
    "waitlist": null,
    "forms": [],
    "documents": ["Medicare card, current plan details, income info if applying for cost-lowering programs (not required for SHIP counseling itself)[3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Delivered via local ADRCs, county aging offices, Tribal offices, senior centers, clinics; plan options vary by county; no wait time differences noted[2][5]",
    "offices_or_providers": ["Bureau of Aging and Disability Resources, 1 West Wilson Street, Rm. 551, P.O. Box 7851, Madison, WI 53707-7851[4]"]
  },
  "official_source": "https://www.dhs.wisconsin.gov/benefit-specialists/medicare-counseling.htm",
  "gotchas": [
    "Counselors do not sell plans or receive company payments—purely unbiased[1][2]",
    "Helps with complex issues like appeals and low-income programs, but families must provide their own Medicare details[3]",
    "Not a healthcare provider; only counseling/enrollment assistance[1]",
    "Plan options change annually and vary by county[2][5]"
  ],
  "data_shape_notes": "no income/asset test; open to all Medicare beneficiaries; services via statewide network of local sites with volunteer counselors; funded by federal grants"
}

{
  "name": "Elder Law Legal Assistance",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income limits stated for legal assistance programs; eligibility often tied to low-income status for free services. Related Medicaid programs (commonly planned for) have asset-focused limits rather than strict income caps, with spousal protections under Spousal Impoverishment Law allowing community spouse to retain portion of income[1][2].",
    "asset_limits": "For associated Medicaid eligibility (frequent focus of elder law help): $2,000 for an individual; $3,000 for a married couple if both applying; approximately $50,000-$120,000 for community spouse. Exemptions and planning strategies (e.g., Spousal Impoverishment protections) apply to avoid destitution; primary home, certain vehicles, and personal items often exempt via attorney planning[1].",
    "other_requirements": ["Wisconsin resident", "Legal issues related to elder rights, public benefits (e.g., Medicaid, SSI), abuse/neglect, advance directives, guardianship, long-term care waivers (Family Care, IRIS, PACE), housing, or age discrimination[2][4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free or low-cost legal advice, representation, or attorney services for: abuse/neglect, powers of attorney, living wills, health care proxies, Medicaid/Family Care eligibility and planning, long-term care waivers (Family Care, Partnership, IRIS, PACE), guardianship, estate planning, public benefits appeals (SSI, BadgerCare), debt collection, age discrimination, involuntary discharges/evictions. No fixed dollar amounts or hours specified; case-by-case assistance[2][4][5][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Legal Action of Wisconsin at 855-947-2529", "Website: legalaction.org", "In-person: Offices in Green Bay, La Crosse, Madison, Milwaukee, Oshkosh, Racine (Milwaukee Senior Law specifically for Milwaukee County residents 60+ on public benefits/elder rights)", "Phone for age discrimination: Dept. of Workforce Development at 608-266-3131", "State Bar Lawyer Referral: 800-362-9082 or wisbar.org/forPublic/INeedaLawyer", "Modest Means Program: wisbar.org/forPublic/INeedaLawyer/pages/modest-means"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["No specific form names/numbers identified; intake via phone/website"],
    "documents": ["Proof of age (e.g., ID), income/asset documentation for benefits-related cases, details of legal issue (e.g., Medicaid denial letters, POA drafts, abuse reports), residency proof[2][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Some services Milwaukee County-specific (e.g., Senior Law via Legal Action); others statewide via phone/referral",
    "regional_variations": "Provider offices vary: Legal Action offices in Green Bay, La Crosse, Madison, Milwaukee, Oshkosh, Racine; county veteran officers for VA benefits; potential differences in wait times/caseloads by region not detailed[2][4]",
    "offices_or_providers": ["Legal Action of Wisconsin (multiple offices)", "State Bar of Wisconsin referrals", "Disability Rights Wisconsin", "County/Tribal veteran service officers"]
  },
  "official_source": "https://www.dhs.wisconsin.gov/aging/legal-assistance.htm",
  "gotchas": ["Not a single 'program' but network of free/low-cost legal services; often requires low-income qualification (varies by provider, e.g., Modest Means for moderate income). Focuses on planning for Medicaid's strict asset rules—DIY planning risks penalties or higher costs; must identify client clearly amid family involvement to avoid capacity/undue influence issues. Medicaid recovery of benefits post-death if no planning. Age discrimination at work handled separately[1][2][3]"],
  "data_shape_notes": "Decentralized network of providers (e.g., Legal Action of WI as primary) rather than unified program; eligibility prioritizes low-income elders 60+ with specific legal needs; heavy tie-in to Medicaid asset planning (no fixed income table, spousal variations); regional offices with some county restrictions like Milwaukee Senior Law"
}

{
  "name": "Elder Benefit Specialist (EBS) Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits; open to all eligible individuals regardless of income[1][2][8]",
    "asset_limits": "No asset limits; open to all eligible individuals regardless of assets[1][2][8]",
    "other_requirements": ["Live in Wisconsin[1]", "Seeking assistance with public or private benefits, health insurance, consumer issues, or related problems[1][2]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Trusted and confidential advice, counseling, assistance with applications and paperwork, screening for entitlement, advocacy for denials or problems (including appeals), information on programs like Medicare, Medicaid, Social Security, SSI, FoodShare, housing, debt collection, consumer fraud; supervised by elder law attorneys; free service (donations welcomed but not required)[1][2][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Find local specialist via https://www.dhs.wisconsin.gov/benefit-specialists/ebs.htm (includes 'Find a benefit specialist near you' tool)[1]", "Contact county aging office, Aging and Disability Resource Center (ADRC), or human/social services department[2][4]", "Phone example: Bureau of Aging and Disability Resources at 608-266-2536 (for general info)[4]", "In-person at local county aging offices or ADRCs[2][4][5]"],
    "processing_time": "Not specified; services provided upon contact as counseling and assistance, not a formal benefits approval process[1][2]",
    "waitlist": null,
    "forms": ["No specific application form required; may sign release of information form for specialist to inquire on behalf[5]", "P-03712F Elder Benefit Specialist Program Brochure available for info[1]"],
    "documents": ["No standard documents required to start; bring info on specific benefits/issues; may need release of information signed[5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide including tribal areas[1][2][3]",
    "regional_variations": "Primarily located in county aging offices, ADRCs, or human/social service departments; tribal variations (e.g., GLITC serves 11 tribes, age 55+ for some tribal elders); different local providers/supervisors but same core services and training[2][3][4][5]",
    "offices_or_providers": ["County aging offices/ADRCs statewide; examples: Walworth County, Crawford County, Chippewa County, Columbia County, Price County; tribal via GLITC[3][4][5][6][8][9]"]
  },
  "official_source": "https://www.dhs.wisconsin.gov/benefit-specialists/ebs.htm",
  "gotchas": ["Not a direct benefits program—provides advice/help applying to other programs, not cash/services itself[1][2]", "Only the individual (or their activated Power of Attorney for Finance) can initiate contact to protect confidentiality/autonomy; family can't apply on their behalf without permission[6]", "Free but donations encouraged; service not refused if no donation[2][5]", "For ages 60+ only (use Disability Benefit Specialist for 18-59)[1][7]", "Tribal programs may have slight age variations (e.g., 55+)[3]"],
  "data_shape_notes": "No financial eligibility test; advisory/advocacy service delivered via local county/tribal offices statewide; not a benefit payer but helper for other programs like Medicare/Medicaid/SSI"
}
